import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const GroupDetail: React.FC<{ user: any }> = ({ user }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [club, setClub] = useState<any>(null);
  const [contribution, setContribution] = useState('');

  // Mock data fetching
  useEffect(() => {
    // In a real app, this would be an API call
    const savedUser = JSON.parse(localStorage.getItem('tf_user') || '{}');
    fetch(`http://localhost:5001/api/users/${savedUser.id}/dashboard`)
      .then(res => res.json())
      .then(data => {
        const found = data.clubs.find((c: any) => c.id === id);
        setClub(found);
      });
  }, [id]);

  const [showMpesaModal, setShowMpesaModal] = useState(false);
  const [mpesaAmount, setMpesaAmount] = useState('');
  const [mpesaPin, setMpesaPin] = useState('');

  if (!club) return <div className="container">Loading Fom Group...</div>;

  const handlePay = () => {
    // Mock payment logic
    const amount = parseFloat(contribution);
    if (!amount) return;

    setClub((prev: any) => ({
      ...prev,
      currentAmount: prev.currentAmount + amount
    }));
    setContribution('');
    alert('Mock Payment Successful!');
  };

  const handleMpesaPayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!mpesaAmount || !mpesaPin) return;

    // Placeholder for Daraja API Call
    console.log(`Daraja API Request: Pay KES ${mpesaAmount} with PIN ${mpesaPin}`);

    // Mock update
    setClub((prev: any) => ({
      ...prev,
      currentAmount: prev.currentAmount + parseFloat(mpesaAmount)
    }));

    setShowMpesaModal(false);
    setMpesaAmount('');
    setMpesaPin('');
    alert(`STK Push Sent to your phone! \n(Daraja API Integration Placeholder)`);
  };

  return (
    <div className="container">
      <header className="flex-between" style={{ padding: '20px 0' }}>
        <button onClick={() => navigate('/dashboard')} style={{ background: 'none' }}>← Back</button>
        <h3>{club.name}</h3>
        <button style={{ background: 'none' }}>⚙️ Settings</button>
      </header>

      <section className="card text-center">
        <div style={{ position: 'relative', display: 'inline-block', marginBottom: '20px' }}>
          <svg width="120" height="120">
            <circle cx="60" cy="60" r="50" stroke="#eee" strokeWidth="10" fill="none" />
            <circle 
              cx="60" cy="60" r="50" 
              stroke="var(--secondary)" 
              strokeWidth="10" 
              fill="none" 
              strokeDasharray="314" 
              strokeDashoffset={314 - (314 * Math.min(1, club.currentAmount / club.targetAmount))}
              style={{ transition: 'stroke-dashoffset 0.5s ease-out', transform: 'rotate(-90deg)', transformOrigin: 'center' }}
            />
          </svg>
          <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', fontWeight: 'bold', fontSize: '1.2rem' }}>
            {Math.round((club.currentAmount / club.targetAmount) * 100)}%
          </div>
        </div>
        <h4>Collected: KES {club.currentAmount} / {club.targetAmount}</h4>
        <p style={{ fontSize: '0.8rem', opacity: 0.7 }}>Target: {club.targetAmount}</p>
      </section>

      <section className="card">
        <h3>Members</h3>
        <div style={{ marginTop: '10px' }}>
          {/* Mock Member List */}
          <div className="flex-between" style={{ padding: '10px 0', borderBottom: '1px solid #eee' }}>
            <span>{user.name} (You)</span>
            <span style={{ color: 'var(--success)', fontWeight: 'bold' }}>KES {club.currentAmount}</span>
          </div>
          <div className="flex-between" style={{ padding: '10px 0', opacity: 0.5 }}>
            <span>Friend 1</span>
            <span>KES 0</span>
          </div>
        </div>
      </section>

      <section className="card">
        <h3>Contribution</h3>
        <div className="input-group">
          <label>Manual Amount (KES)</label>
          <input type="number" value={contribution} onChange={(e) => setContribution(e.target.value)} placeholder="0.00" />
        </div>
        <button className="primary" style={{ width: '100%', marginBottom: '10px' }} onClick={handlePay}>Contribute Manually</button>

        <div style={{ borderTop: '1px solid #eee', margin: '15px 0', paddingTop: '15px' }}>
          <button 
            className="secondary" 
            style={{ width: '100%', background: '#00C323', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }} 
            onClick={() => setShowMpesaModal(true)}
          >
            <span style={{ fontWeight: 'bold' }}>Lipa na M-PESA</span>
          </button>
        </div>
      </section>

      {/* M-PESA Placeholder Modal */}
      {showMpesaModal && (
        <div style={{
          position: 'fixed', top: 0, left: 0, width: '100%', height: '100%',
          background: 'rgba(0,0,0,0.5)', display: 'grid', placeContent: 'center', zIndex: 1000
        }}>
          <div className="card" style={{ width: '320px', margin: 0 }}>
            <h3 style={{ color: '#00C323' }}>M-PESA Payment</h3>
            <p style={{ fontSize: '0.8rem', marginBottom: '15px' }}>Enter details to trigger STK Push</p>

            <form onSubmit={handleMpesaPayment}>
              <div className="input-group">
                <label>Amount (KES)</label>
                <input 
                  type="number" 
                  value={mpesaAmount} 
                  onChange={(e) => setMpesaAmount(e.target.value)} 
                  placeholder="e.g. 500" 
                  required 
                />
              </div>
              <div className="input-group">
                <label>M-PESA PIN (Placeholder)</label>
                <input 
                  type="password" 
                  value={mpesaPin} 
                  onChange={(e) => setMpesaPin(e.target.value)} 
                  placeholder="****" 
                  maxLength={4}
                  required 
                />
              </div>
              <button type="submit" className="secondary" style={{ width: '100%', background: '#00C323' }}>
                Confirm Payment
              </button>
              <button 
                type="button" 
                style={{ width: '100%', background: 'none', marginTop: '10px', color: '#666' }} 
                onClick={() => setShowMpesaModal(false)}
              >
                Cancel
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="text-center" style={{ margin: '20px' }}>
        <p style={{ fontSize: '0.9rem', color: '#666' }}>Share this Club ID with friends to join:</p>
        <code style={{ background: '#eee', padding: '5px 15px', borderRadius: '5px', fontSize: '1.1rem', fontWeight: 'bold', display: 'inline-block', marginTop: '10px' }}>
            {club.clubId}
        </code>
      </div>
    </div>
  );
};

export default GroupDetail;
